using System;
using System.Collections.Generic;
using System.IO;
using System.Xml;

public class XmlConfigParser
{
    /// <summary>
    /// Parses an XML configuration file and extracts settings into a Dictionary.
    /// Supports external DTD validation when referenced in the XML.
    /// </summary>
    /// <param name="xmlContent">The XML content as a string</param>
    /// <param name="baseUri">Optional base URI for resolving relative paths to DTDs</param>
    /// <returns>Dictionary containing the extracted configuration settings</returns>
    public Dictionary<string, string> ParseConfiguration(string xmlContent, string baseUri = null)
    {
        if (string.IsNullOrWhiteSpace(xmlContent))
        {
            throw new ArgumentException("XML content cannot be null or empty.", nameof(xmlContent));
        }

        var settings = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

        // Configure XmlReaderSettings for secure parsing with DTD support
        var readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD,
            MaxCharactersFromEntities = 1024,  // Limit entity expansion to prevent DoS
            MaxCharactersInDocument = 10 * 1024 * 1024, // 10MB document limit
            XmlResolver = new XmlUrlResolver() // Allows resolving external DTDs
        };

        // Add validation event handler for DTD validation errors
        var validationErrors = new List<string>();
        readerSettings.ValidationEventHandler += (sender, e) =>
        {
            if (e.Severity == System.Xml.Schema.XmlSeverityType.Error)
            {
                validationErrors.Add($"Validation Error: {e.Message} at line {e.Exception?.LineNumber}");
            }
            else
            {
                validationErrors.Add($"Validation Warning: {e.Message}");
            }
        };

        XmlDocument xmlDoc = new XmlDocument();
        xmlDoc.XmlResolver = new XmlUrlResolver(); // Allow DTD resolution

        using (var stringReader = new StringReader(xmlContent))
        {
            var parserContext = new XmlParserContext(null, null, null, XmlSpace.Default);
            if (!string.IsNullOrEmpty(baseUri))
            {
                parserContext.BaseURI = baseUri;
            }

            using (var xmlReader = XmlReader.Create(stringReader, readerSettings))
            {
                xmlDoc.Load(xmlReader);
            }
        }

        if (validationErrors.Count > 0)
        {
            throw new XmlException(
                $"DTD validation failed with {validationErrors.Count} error(s): " +
                string.Join("; ", validationErrors));
        }

        // Extract settings from the XML document
        XmlElement root = xmlDoc.DocumentElement;
        if (root == null)
        {
            throw new XmlException("XML document has no root element.");
        }

        // Recursively extract all settings
        ExtractSettings(root, settings, string.Empty);

        return settings;
    }

    /// <summary>
    /// Parses an XML configuration file from a file path.
    /// </summary>
    /// <param name="filePath">Path to the XML configuration file</param>
    /// <returns>Dictionary containing the extracted configuration settings</returns>
    public Dictionary<string, string> ParseConfigurationFromFile(string filePath)
    {
        if (!File.Exists(filePath))
        {
            throw new FileNotFoundException("Configuration file not found.", filePath);
        }

        string xmlContent = File.ReadAllText(filePath);
        string baseUri = Path.GetDirectoryName(Path.GetFullPath(filePath));
        return ParseConfiguration(xmlContent, baseUri);
    }

    /// <summary>
    /// Parses an XML configuration from a Stream.
    /// </summary>
    /// <param name="xmlStream">Stream containing the XML content</param>
    /// <param name="baseUri">Optional base URI for resolving relative DTD paths</param>
    /// <returns>Dictionary containing the extracted configuration settings</returns>
    public Dictionary<string, string> ParseConfigurationFromStream(Stream xmlStream, string baseUri = null)
    {
        if (xmlStream == null)
        {
            throw new ArgumentNullException(nameof(xmlStream));
        }

        using (var reader = new StreamReader(xmlStream))
        {
            string xmlContent = reader.ReadToEnd();
            return ParseConfiguration(xmlContent, baseUri);
        }
    }

    /// <summary>
    /// Recursively extracts settings from XML elements into the dictionary.
    /// Uses dot-notation for nested element paths (e.g., "database.connection.host").
    /// Attributes are stored with @ prefix (e.g., "database.connection.@timeout").
    /// </summary>
    private void ExtractSettings(XmlNode node, Dictionary<string, string> settings, string parentPath)
    {
        if (node == null) return;

        string currentPath = string.IsNullOrEmpty(parentPath)
            ? node.Name
            : $"{parentPath}.{node.Name}";

        // Extract attributes
        if (node.Attributes != null)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string attrKey = $"{currentPath}.@{attr.Name}";
                settings[attrKey] = attr.Value;
            }
        }

        // Check if this is a leaf node (contains only text, no child elements)
        bool hasChildElements = false;
        if (node.HasChildNodes)
        {
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    hasChildElements = true;
                    break;
                }
            }
        }

        if (!hasChildElements)
        {
            // Leaf node — store the text content
            string textContent = node.InnerText?.Trim();
            if (textContent != null)
            {
                // Handle duplicate keys by tracking count
                if (settings.ContainsKey(currentPath))
                {
                    // Find a unique key with an index suffix
                    int index = 1;
                    string uniqueKey;
                    do
                    {
                        uniqueKey = $"{currentPath}[{index}]";
                        index++;
                    } while (settings.ContainsKey(uniqueKey));

                    // Rename the original key if this is the first duplicate
                    if (!settings.ContainsKey($"{currentPath}[0]"))
                    {
                        settings[$"{currentPath}[0]"] = settings[currentPath];
                    }

                    settings[uniqueKey] = textContent;
                }
                else
                {
                    settings[currentPath] = textContent;
                }
            }
        }
        else
        {
            // Has child elements — recurse into them
            // Track element name occurrences for handling repeated elements
            var elementCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    if (!elementCounts.ContainsKey(child.Name))
                    {
                        elementCounts[child.Name] = 0;
                    }

                    // Count how many siblings share the same name
                    int sameNameCount = 0;
                    foreach (XmlNode sibling in node.ChildNodes)
                    {
                        if (sibling.NodeType == XmlNodeType.Element &&
                            string.Equals(sibling.Name, child.Name, StringComparison.OrdinalIgnoreCase))
                        {
                            sameNameCount++;
                        }
                    }

                    if (sameNameCount > 1)
                    {
                        // Multiple elements with the same name — use indexed path
                        string indexedPath = string.IsNullOrEmpty(currentPath)
                            ? $"{child.Name}[{elementCounts[child.Name]}]"
                            : $"{currentPath}.{child.Name}[{elementCounts[child.Name]}]";

                        ExtractSettingsWithExplicitPath(child, settings, indexedPath);
                        elementCounts[child.Name]++;
                    }
                    else
                    {
                        ExtractSettings(child, settings, currentPath);
                    }
                }
                else if (child.NodeType == XmlNodeType.Text || child.NodeType == XmlNodeType.CDATA)
                {
                    // Mixed content — store the text portion
                    string text = child.Value?.Trim();
                    if (!string.IsNullOrEmpty(text))
                    {
                        settings[$"{currentPath}.#text"] = text;
                    }
                }
            }
        }
    }

    /// <summary>
    /// Extracts settings with an explicitly provided path (used for indexed/repeated elements).
    /// </summary>
    private void ExtractSettingsWithExplicitPath(XmlNode node, Dictionary<string, string> settings, string explicitPath)
    {
        if (node == null) return;

        // Extract attributes
        if (node.Attributes != null)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string attrKey = $"{explicitPath}.@{attr.Name}";
                settings[attrKey] = attr.Value;
            }
        }

        bool hasChildElements = false;
        if (node.HasChildNodes)
        {
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    hasChildElements = true;
                    break;
                }
            }
        }

        if (!hasChildElements)
        {
            string textContent = node.InnerText?.Trim();
            if (textContent != null)
            {
                settings[explicitPath] = textContent;
            }
        }
        else
        {
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    string childPath = $"{explicitPath}.{child.Name}";
                    ExtractSettingsWithExplicitPath(child, settings, childPath);
                }
            }
        }
    }
}

